UPDATE articles SET content = '[{"id":"a1","type":"paragraph","text":"В случайном месте на карте с орбиты падают обломки спутника."},{"id":"a2","type":"warning","icon":"Опасность!","text":"Зона падения защищена патрульным вертолетом, турелями и минами."},{"id":"a3","type":"heading2","text":"☄️ Как проходит ивент"},{"id":"a4","type":"list","ordered":false,"items":["**Обнаружение:** Спутник падает в случайной точке. Ищите место на карте.","**Зачистка:** Уничтожьте патрульный вертолёт и зачистите территорию от NPC-Космонавтов. Будьте осторожны — земля вокруг может быть заминирована!","**Сбор ящиков:** Часть ящиков в свободном доступе рядом с обломками, но самый ценный лут закрыт — открывается только космической картой."]},{"id":"a5","type":"heading2","text":"🔑 Система доступа"},{"id":"a6","type":"paragraph","text":"Основная добыча заперта в отсеке спутника. Обычные карты не подойдут."},{"id":"a7","type":"tip","icon":"Ключ к успеху","text":"Найдите **Космическую карту** в Радиоактивных обломках. Только с её помощью можно активировать терминал возле закрытого ящика и забрать финальные награды."},{"id":"a8","type":"heading2","text":"⚠️ Основные угрозы"},{"id":"a9","type":"list","ordered":false,"items":["**Патрульный вертолет:** Кружит над местом падения, поддерживает NPC с воздуха.","**Элитные NPC (Космонавты):** Больше здоровья, чем у обычных — берите больше патронов.","**Турели:** Не пытайтесь пробежать мимо — расстреливают почти мгновенно.","**Мины:** Всегда смотрите под ноги при приближении к эпицентру."]}]'
WHERE id = 22;

UPDATE articles SET content = '[{"id":"b1","type":"paragraph","text":"Группа мусорщиков заняла локацию **Свалка**. Они спрятали сигнальную гранату для вызова припасов в одном из старых авто. Ваша задача — найти её и перехватить ценный груз."},{"id":"b2","type":"heading2","text":"🏗️ Этап 1 — Поиск сигнала"},{"id":"b3","type":"paragraph","text":"Сигнальная граната спрятана в **случайной ржавой машине** на территории свалки. Чтобы её достать, машину нужно уничтожить."},{"id":"b4","type":"step","stepNum":1,"text":"Зачистите свалку от NPC-мусорщиков."},{"id":"b5","type":"step","stepNum":2,"text":"Садитесь в **магнитный кран** и поочередно грузите ржавые авто в **измельчитель (Shredder)**."},{"id":"b6","type":"step","stepNum":3,"text":"Перерабатывайте машины одну за другой, пока не сработает скрытая сигнальная граната."},{"id":"b7","type":"heading2","text":"✈️ Этап 2 — Перехват грузовика"},{"id":"b8","type":"paragraph","text":"После активации сигнала прилетит самолёт и сбросит на парашюте целый **грузовик с припасами**."},{"id":"b9","type":"list","ordered":false,"items":["**Охрана:** Из грузовика выйдут вооружённые защитники. Убейте их всех.","**Взлом:** Грузовик заперт, обычными способами не открыть."]},{"id":"b10","type":"heading2","text":"⚙️ Этап 3 — Финальная переработка"},{"id":"b11","type":"paragraph","text":"С помощью крана поднимите **грузовик целиком** и отправьте его в измельчитель. Только так вы разрушите корпус и пустите ящики по **конвейерной ленте**, где их можно обыскать."},{"id":"b12","type":"tip","icon":"Совет","text":"Научитесь управлять краном заранее — это сэкономит много времени в самый ответственный момент!"}]'
WHERE id = 23;

UPDATE articles SET content = '[{"id":"c1","type":"paragraph","text":"Учёные в спешке покинули Арктику из-за нападения диких зверей, бросив ценную **буровую установку**. Ваша задача — найти её местоположение и запустить добычу ресурсов."},{"id":"c2","type":"heading2","text":"❄️ Этап 1 — Поиск сигнала"},{"id":"c3","type":"paragraph","text":"Чтобы определить координаты установки, нужно активировать **три приёмника сигнала** в разных частях острова."},{"id":"c4","type":"step","stepNum":1,"text":"🛰️ **Сканирование:** Найдите приёмник и запустите процесс. Работа устройства сводит с ума местных животных — они немедленно атакуют сканер."},{"id":"c5","type":"step","stepNum":2,"text":"🛡️ **Оборона:** Защищайте приёмник любой ценой. Чем меньше повреждений он получит, тем больше **батареек** вы получите в награду."},{"id":"c6","type":"warning","icon":"Важно!","text":"Вы не найдёте установку, пока не активируете последовательно все три приёмника!"},{"id":"c7","type":"heading2","text":"⛏️ Этап 2 — Запуск буровой установки"},{"id":"c8","type":"paragraph","text":"После активации последнего сканера вы получите координаты самой установки. Теперь применяйте собранные ресурсы."},{"id":"c9","type":"tip","icon":"🔋 Механика батареек","text":"Батарейки выпадают после каждого успешного сканирования. Вставьте все собранные батареи в буровую установку. **Больше батарей = дольше работа = богаче итоговый лут!**"}]'
WHERE id = 24;
